mapper.select:
SELECT 
    a.id, a.application_id, a.student_no, a.expected_return_time, a.reason, 
    a.destination, a.description, a.attachment_url, a.apply_time, a.audit_status, 
    a.audit_time, a.audit_person, a.audit_remark,
    s.name as student_name, s.college, s.dormitory
FROM application a
LEFT JOIN student s ON a.student_no = s.student_no


        AND a.id = #{id}


        AND a.application_id = #{applicationId}


        AND a.student_no = #{studentNo}


        AND a.expected_return_time = #{expectedReturnTime}


        AND a.reason = #{reason}


        AND a.attachment_url = #{attachmentUrl}


        AND a.apply_time = #{applyTime}


        AND a.audit_status = #{auditStatus}


        AND a.audit_time = #{auditTime}


        AND a.audit_person = #{auditPerson}


        AND a.audit_remark = #{auditRemark}




        AND a.student_no IN

            #{item}



        AND a.audit_status IN

            #{item}



        AND a.audit_person IN

            #{item}





        AND a.expected_return_time >= #{expectedReturnTimeStart}


        AND a.expected_return_time <= #{expectedReturnTimeEnd}


        AND a.apply_time >= #{applyTimeStart}


        AND a.apply_time <= #{applyTimeEnd}


        AND a.audit_time >= #{auditTimeStart}


        AND a.audit_time <= #{auditTimeEnd}




        AND a.reason LIKE CONCAT('%', #{reasonLike}, '%')


ORDER BY a.apply_time DESC

update.foreach:
UPDATE application
application_id = #{item.applicationId}, student_no = #{item.studentNo}, expected_return_time = #{item.expectedReturnTime}, reason = #{item.reason}, destination = #{item.destination}, description = #{item.description}, attachment_url = #{item.attachmentUrl}, apply_time = #{item.applyTime}, audit_status = #{item.auditStatus}, audit_time = #{item.auditTime}, audit_person = #{item.auditPerson}, audit_remark = #{item.auditRemark},
WHERE id = #{item.id}
